#include <bits/stdc++.h>
using namespace std;

const int N=1e5+5;

int n,m,g[27],f[N],ans=2e9;
char s[N];
bool b[27][27];

int main(){
    scanf("%d%s%d",&n,s+1,&m);
    while(m--){
        char x[2];
        scanf("%s",x);
        b[x[0]-'a'][x[1]-'a']=b[x[1]-'a'][x[0]-'a']=1;
    }
    memset(g,0x3f,sizeof(g));
    for(int i=1;i<=n;i++){
        f[i]=i-1;
        for(int j=0;j<26;j++)
            if(!b[j][s[i]-'a'])
                f[i]=min(f[i],g[j]+i-1);
        g[s[i]-'a']=min(g[s[i]-'a'],f[i]-i);
        ans=min(ans,f[i]+n-i);
    }
    printf("%d",ans);
    return 0;
}
